static let textureNames = [
    "deep_star_map_8k", "dual_nebula", "blue_filaments", "teal_orange", "dark_dust", "pale_haze"
]

// §7a — how much real nebulosity/structure each panorama already carries (0 = near-black
// star field, 1 = nebula-filled sky). MEASURED from the panoramas (blurred-luminance mean
// + large-scale variation + non-black coverage), not eyeballed. Index-aligned with
// textureNames. Drives generated-nebula density down (below) so our procedural gas doesn't
// pile onto — and thereby give away — an already-busy real sky.
static let busyness: [Float] = [0.00, 0.80, 0.89, 0.65, 0.28, 0.93]

// Multiplier applied to a config's nebula density for a given backdrop: a quiet sky keeps
// the full range, a busy sky gets a whisper. The freed-up depth cue is the (unchanged,
// dense) L3 star field showing through more clearly — see AppModel.applyNewEnvironment.
static func nebulaScale(forBackdrop index: Int) -> Float {
    let n = textureNames.count
    let b = busyness[((index % n) + n) % n]
    return 1.0 - 0.85 * b            // busy=0 → 1.0, busy=0.93 → ~0.21
}

input.new_string:
/// One panorama in the library. Replaces the old index-aligned `textureNames` +
/// `busyness` arrays — two parallel arrays that had to be edited in lockstep and
/// silently mis-scaled the nebula if they ever drifted. Everything a panorama needs
/// now lives on one row.
struct Panorama: Identifiable, Hashable {
    let name: String        // bundle resource name (Resources/Textures/Backdrop)
    let title: String       // human label, shown in the scene selector
    /// §7a — how much real nebulosity/structure this sky already carries (0 = near-black
    /// star field, 1 = nebula-filled). MEASURED, not eyeballed:
    /// `scripts/backdrop_tool.py measure`, whose coefficients are fitted to the six
    /// values originally tuned by hand here.
    let busyness: Float
    /// True when the panorama has a real horizon and ground. Grounded skies are a
    /// vertigo mitigation: a static horizon is a vestibular rest frame, which is why
    /// §9's comfort intent *favours* them rather than forbidding them. They carry two
    /// hard constraints — see `reskin` (rotation) and `nebulaScale` (clipping).
    let grounded: Bool

    var id: String { name }
}

static let catalog: [Panorama] = [
    // ── Deep space (no horizon) ────────────────────────────────────────────────
    .init(name: "deep_star_map_8k", title: "Deep Star Map",      busyness: 0.00, grounded: false),
    .init(name: "dual_nebula",      title: "Dual Nebula",        busyness: 0.80, grounded: false),
    .init(name: "blue_filaments",   title: "Blue Filaments",     busyness: 0.89, grounded: false),
    .init(name: "teal_orange",      title: "Teal & Orange",      busyness: 0.65, grounded: false),
    .init(name: "dark_dust",        title: "Dark Dust",          busyness: 0.28, grounded: false),
    .init(name: "pale_haze",        title: "Pale Haze",          busyness: 0.93, grounded: false),
    // ── Grounded (real horizon — vertigo mitigation) ───────────────────────────
    .init(name: "ground_rogland_night",    title: "Rogland Desert Night",  busyness: 0.55, grounded: true),
    .init(name: "ground_dikhololo_night",  title: "Dikhololo Night",       busyness: 0.63, grounded: true),
    .init(name: "ground_paranal_vlt",      title: "Paranal — VLT",         busyness: 0.84, grounded: true),
    .init(name: "ground_paranal_lasers",   title: "Paranal — Laser Guide", busyness: 0.65, grounded: true),
    .init(name: "ground_lasilla_arc",      title: "La Silla — Milky Way",  busyness: 0.89, grounded: true),
    .init(name: "ground_lasilla_airglow",  title: "La Silla — Airglow",    busyness: 1.00, grounded: true),
]

/// Indices eligible for the random "New Environment" jump (§7b). Grounded skies are
/// deliberately EXCLUDED: they are an explicit comfort mode, and a random jump either
/// out of one (losing the rest frame someone opted into) or into one (dropping a
/// desert under a deep-space float) is wrong in both directions. Reach them from the
/// scene selector.
static let randomJumpIndices: [Int] = catalog.indices.filter { !catalog[$0].grounded }

static func clampedIndex(_ index: Int) -> Int {
    let n = catalog.count
    return ((index % n) + n) % n
}

static func panorama(at index: Int) -> Panorama { catalog[clampedIndex(index)] }

// Multiplier applied to a config's nebula density for a given backdrop: a quiet sky keeps
// the full range, a busy sky gets a whisper. The freed-up depth cue is the (unchanged,
// dense) L3 star field showing through more clearly — see AppModel.applyNewEnvironment.
static func nebulaScale(forBackdrop index: Int) -> Float {
    let p = panorama(at: index)
    // Grounded skies get NO generated nebula. The L2 volume is a full surround, so it
    // would pass straight through the horizon and hang under the ground — which reads
    // as a rendering fault and undoes the rest frame the ground is there to provide.
    // TODO §4/§9: clamp NebulaVolume to the upper hemisphere, then allow a whisper here.
    if p.grounded { return 0 }
    return 1.0 - 0.85 * p.busyness   // busy=0 → 1.0, busy=0.93 → ~0.21
}

