    /// Shuffle-bag over the backdrops: hand out each panorama once (in a seeded random
    /// order) before refilling, so New Environment cycles through ALL of them. Refill avoids
    /// opening on the sky we just showed, so there are no back-to-back repeats across bags.
    private var backdropBag: [Int] = []
    private func nextBackdrop(rng: inout SeededRandom) -> Int {
        let count = FarBackdrop.textureNames.count
        if backdropBag.isEmpty {
            var bag = Array(0..<count)
            for i in stride(from: count - 1, through: 1, by: -1) {      // Fisher–Yates
                let j = Int(rng.next() % UInt64(i + 1))
                bag.swapAt(i, j)
            }
            // removeLast() serves the pick, so keep bag.last (the next pick) off the current sky.
            if count > 1 && bag.last == currentConfig.backdrop { bag.swapAt(0, count - 1) }
            backdropBag = bag
        }
        return backdropBag.removeLast()
    }
}

input.new_string:
    /// Shuffle-bag over the backdrops: hand out each panorama once (in a seeded random
    /// order) before refilling, so New Environment cycles through ALL of them. Refill avoids
    /// opening on the sky we just showed, so there are no back-to-back repeats across bags.
    /// Draws from `randomJumpIndices` only — grounded skies are never rolled into a jump.
    private var backdropBag: [Int] = []
    private func nextBackdrop(rng: inout SeededRandom) -> Int {
        if backdropBag.isEmpty {
            var bag = FarBackdrop.randomJumpIndices
            let count = bag.count
            for i in stride(from: count - 1, through: 1, by: -1) {      // Fisher–Yates
                let j = Int(rng.next() % UInt64(i + 1))
                bag.swapAt(i, j)
            }
            // removeLast() serves the pick, so keep bag.last (the next pick) off the current sky.
            if count > 1 && bag.last == currentConfig.backdrop { bag.swapAt(0, count - 1) }
            backdropBag = bag
        }
        return backdropBag.removeLast()
    }

    // MARK: - Direct scene selection (§7a) — the test affordance behind SceneSelectorView.

    /// Jump straight to a specific panorama, keeping the current seed so everything else
    /// about the universe (stars, phenomena, hero content) stays put and only the sky
    /// changes. Masked by the same §7b whiteout as a random jump, so selecting a scene is
    /// no less comfortable than jumping to one.
    func showBackdrop(_ index: Int) {
        let idx = FarBackdrop.clampedIndex(index)
        // Selecting a generated scene implies wanting to look at the generated scene.
        if environmentSource != .generated {
            environmentSource = .generated
            applyEnvironmentVisibility()
        }
        maskedSwap { [weak self] in self?.applyBackdrop(idx) }
    }

    /// Show a specific bundled Apple Spatial sky (the imported A/B siblings).
    func showImported(_ index: Int) {
        guard let importedRoot, !SpatialImageEnvironment.resourceNames.isEmpty else { return }
        let count = SpatialImageEnvironment.resourceNames.count
        importedIndex = ((index % count) + count) % count
        if environmentSource != .importedSpatial {
            environmentSource = .importedSpatial
            applyEnvironmentVisibility()
        }
        maskedSwap {
            Task { @MainActor in
                await SpatialImageEnvironment.load(index: self.importedIndex, into: importedRoot)
            }
        }
    }

    /// Run `swap` under the peak of the §7b whiteout flash. Falls back to applying it
    /// immediately if the overlay isn't mounted yet, so selection still works pre-scene.
    private func maskedSwap(_ swap: @escaping @MainActor () -> Void) {
        guard let whiteout else { swap(); return }
        if whiteout.components[WhiteoutComponent.self]?.active == true { return }
        var c = whiteout.components[WhiteoutComponent.self] ?? WhiteoutComponent()
        c.active = true; c.elapsed = 0
        whiteout.components.set(c)
        Task { @MainActor in
            try? await Task.sleep(for: .seconds(0.30))
            swap()
        }
    }

    /// Re-skin the backdrop to `index` in place and rebuild the nebula for it. Same light
    /// path as `applyNewEnvironment` (never a full scene rebuild — that crashed the device
    /// render server), but the seed is untouched so only the sky changes.
    private func applyBackdrop(_ index: Int) {
        guard let container = sceneContainer,
              let root = container.children.first(where: { $0.name == "UniverseRoot" }) else { return }

        var newConfig = currentConfig
        newConfig.backdrop = index
        // Re-derive density for the new sky so §7a busyness suppression still applies (and
        // so a grounded pick drops the nebula to zero rather than hanging it under the ground).
        var rng = SeededRandom(seed: currentConfig.seed ^ 0x5343_454E_5F53_454C)   // "SCEN_SEL"
        newConfig.nebulaDensity = rng.unit() * FarBackdrop.nebulaScale(forBackdrop: index)
        currentConfig = newConfig

        let gen = EnvironmentGenerator(config: newConfig)
        if let backdrop = root.findEntity(named: "L1_Backdrop") as? ModelEntity {
            FarBackdrop.reskin(backdrop, gen: gen)
        }
        root.children.filter { $0.name.hasPrefix("L2_Nebula") }.forEach { $0.removeFromParent() }
        root.addChild(NebulaVolume.make(gen: gen))
    }
}

