input.content:
import SwiftUI

/// Direct scene picker (§7a) — a test affordance, not part of the immersive experience.
///
/// "New Environment" (§7b) is deliberately a *random* jump, which is right for using the
/// app and wrong for working on it: getting back to one specific sky meant jumping until
/// it came round again. This lists every panorama by name so any one of them is one tap
/// away, and it lives in its own window so it can be opened while already inside the
/// immersive space (same pattern as the reader panel).
///
/// Grounded skies are listed in their own section because they are a different mode, not
/// just different art — see `FarBackdrop.Panorama.grounded`.
struct SceneSelectorView: View {
    @Environment(AppModel.self) private var model
    @State private var query = ""

    private var spaceScenes: [(offset: Int, element: FarBackdrop.Panorama)] {
        filtered(FarBackdrop.catalog.enumerated().filter { !$0.element.grounded })
    }

    private var groundedScenes: [(offset: Int, element: FarBackdrop.Panorama)] {
        filtered(FarBackdrop.catalog.enumerated().filter { $0.element.grounded })
    }

    private func filtered(
        _ items: [(offset: Int, element: FarBackdrop.Panorama)]
    ) -> [(offset: Int, element: FarBackdrop.Panorama)] {
        guard !query.isEmpty else { return items }
        return items.filter { $0.element.title.localizedCaseInsensitiveContains(query) }
    }

    private var importedScenes: [(offset: Int, element: String)] {
        let all = Array(SpatialImageEnvironment.resourceNames.enumerated())
            .map { (offset: $0.offset, element: $0.element) }
        guard !query.isEmpty else { return all }
        return all.filter { $0.element.localizedCaseInsensitiveContains(query) }
    }

    var body: some View {
        NavigationStack {
            List {
                if !spaceScenes.isEmpty {
                    Section("Deep Space") {
                        ForEach(spaceScenes, id: \.element.id) { item in
                            row(title: item.element.title,
                                subtitle: busynessLabel(item.element.busyness),
                                isCurrent: isCurrentGenerated(item.offset)) {
                                model.showBackdrop(item.offset)
                            }
                        }
                    }
                }

                if !groundedScenes.isEmpty {
                    Section {
                        ForEach(groundedScenes, id: \.element.id) { item in
                            row(title: item.element.title,
                                subtitle: "horizon · no nebula",
                                isCurrent: isCurrentGenerated(item.offset)) {
                                model.showBackdrop(item.offset)
                            }
                        }
                    } header: {
                        Text("Grounded")
                    } footer: {
                        Text("A static horizon gives a fixed reference frame — the option to try if floating brings on vertigo.")
                    }
                }

                if !importedScenes.isEmpty {
                    Section("Imported (Apple Spatial)") {
                        ForEach(importedScenes, id: \.element) { item in
                            row(title: item.element.replacingOccurrences(of: "_", with: " ").capitalized,
                                subtitle: "stereo 360",
                                isCurrent: model.environmentSource == .importedSpatial
                                    && model.importedIndex == item.offset) {
                                model.showImported(item.offset)
                            }
                        }
                    }
                }
            }
            .searchable(text: $query, prompt: "Find a scene")
            .navigationTitle("Scenes")
            .overlay {
                if spaceScenes.isEmpty && groundedScenes.isEmpty && importedScenes.isEmpty {
                    ContentUnavailableView.search(text: query)
                }
            }
        }
        .frame(minWidth: 360, minHeight: 420)
    }

    private func isCurrentGenerated(_ index: Int) -> Bool {
        model.environmentSource == .generated && model.currentConfig.backdrop == index
    }

    /// Surfaces the §7a suppression rule that is otherwise invisible: a busy sky means the
    /// generated nebula is turned down, so "why is there no nebula here" has an answer on
    /// screen instead of only in DepthLayers.
    private func busynessLabel(_ b: Float) -> String {
        switch b {
        case ..<0.15: return "quiet sky · full nebula"
        case ..<0.55: return "some structure · reduced nebula"
        default:      return "busy sky · nebula suppressed"
        }
    }

    @ViewBuilder
    private func row(title: String, subtitle: String,
                     isCurrent: Bool, action: @escaping () -> Void) -> some View {
        Button(action: action) {
            HStack {
                VStack(alignment: .leading, spacing: 2) {
                    Text(title)
                    Text(subtitle).font(.caption).foregroundStyle(.secondary)
                }
                Spacer()
                if isCurrent {
                    Image(systemName: "checkmark.circle.fill")
                        .foregroundStyle(.tint)
                        .accessibilityLabel("Currently showing")
                }
            }
            .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
    }
}

