        # Per-eye selection: camera index 0 = left, 1 = right, mono/default = left.
        def Shader "EyeSwitch"
        {
            uniform token info:id = "ND_realitykit_geometry_switch_cameraindex_color3"
            color3f inputs:mono.connect = </Root/Stereo360/LeftImage.outputs:out>
            color3f inputs:left.connect = </Root/Stereo360/LeftImage.outputs:out>
            color3f inputs:right.connect = </Root/Stereo360/RightImage.outputs:out>
            color3f outputs:out
        }

        def Shader "LeftImage"
        {
            uniform token info:id = "ND_image_color3"
            asset inputs:file.connect = </Root/Stereo360.inputs:LeftEye>
            color3f outputs:out
        }

