import RealityKit
import UIKit

// §7b whiteout — a brief full-view white flash that masks a scene change. Kept from the
// (now retired) generated L1–L4 pipeline because the spatial-image scene system still uses
// it to mask a jump/select between skies. Everything else that lived here — the generated
// far backdrop, L2 nebula (splat/particle), L3 star volume, L4 phenomena — was removed when
// the app moved to a pre-rendered stereo-image library (see SpatialImageEnvironment).
struct WhiteoutComponent: Component {
    var active = false
    var elapsed: TimeInterval = 0
    var fadeIn: TimeInterval = 0.25
    var hold: TimeInterval = 0.12
    var fadeOut: TimeInterval = 0.45
    var total: TimeInterval { fadeIn + hold + fadeOut }
}

struct WhiteoutSystem: System {
    static let query = EntityQuery(where: .has(WhiteoutComponent.self))
    init(scene: Scene) {}
    func update(context: SceneUpdateContext) {
        MainActor.assumeIsolated {
            for e in context.entities(matching: Self.query, updatingSystemWhen: .rendering) {
                guard var c = e.components[WhiteoutComponent.self], c.active,
                      let me = e as? ModelEntity else { continue }
                c.elapsed += context.deltaTime
                var a: Float
                if c.elapsed < c.fadeIn {
                    a = Float(c.elapsed / c.fadeIn)                                   // fade to white
                } else if c.elapsed < c.fadeIn + c.hold {
                    a = 1                                                            // peak (swap happens here)
                } else if c.elapsed < c.total {
                    a = Float(1 - (c.elapsed - c.fadeIn - c.hold) / c.fadeOut)         // reveal new env
                } else {
                    a = 0; c.active = false
                }
                a = max(0, min(1, a))
                var mat = UnlitMaterial()
                mat.color = .init(tint: UIColor(white: 1, alpha: CGFloat(a)), texture: nil)
                mat.blending = .transparent(opacity: 1.0)
                me.model?.materials = [mat]
                e.components[WhiteoutComponent.self] = c
            }
        }
    }

    // Inward white sphere just inside all content; alpha 0 until a jump flashes it (§7b).
    @MainActor
    static func makeEntity() -> ModelEntity {
        var mat = UnlitMaterial()
        mat.color = .init(tint: UIColor(white: 1, alpha: 0), texture: nil)
        mat.blending = .transparent(opacity: 1.0)
        let e = ModelEntity(mesh: .generateSphere(radius: 1.5), materials: [mat])
        e.name = "Whiteout"
        e.scale.z = -1   // render the inside
        e.components.set(WhiteoutComponent())
        return e
    }
}

import Foundation

/// §7e — a saved "Place". Since the app moved from a seed-generated universe to a fixed
/// library of pre-rendered stereo skies, a Place is no longer a seed + generation params —
/// it is simply *which sky* (by its bundle resource name) plus a display label and thumbnail.
/// The old deterministic-restore machinery (simTime / generatorVersion / seed) is gone with
/// the generated scene.
struct SavedLocation: Codable, Identifiable {
    var id: UUID = UUID()
    var sceneName: String        // SpatialImageEnvironment resource name
    var label: String            // user-facing name in the gallery
    var thumbnailFile: String    // the gallery thumbnail
    var createdAtEpoch: Double   // wall-clock label only
}

/// Loads/saves Places.
@MainActor
final class SavedLocationStore {
    // TODO: persist [SavedLocation] via Codable JSON + thumbnail image files (or SwiftData).
    func save(_ loc: SavedLocation) { /* TODO */ }
    func load() -> [SavedLocation] { [] }
}

import SwiftUI
import RealityKit
import ARKit
import simd

/// §7 — reveal gesture. Two thumb+index pinch/release cycles within ~350–450 ms.
/// WARNING: a single pinch is the system "tap" — arm this only when gaze is off UI (§7).
@MainActor
final class DoublePinchDetector {
    var onDoublePinch: (() -> Void)?
    private var lastPinchEndTime: Double?

    // Hysteresis thresholds (metres) so one slow pinch isn't read as two.
    private let pinchOn: Float = 0.015
    private let pinchOff: Float = 0.03

    func ingest(thumbTip: SIMD3<Float>, indexTip: SIMD3<Float>, time: Double) {
        // TODO: detect pinch enter/exit via distance + hysteresis; if two cycles land
        //       inside the window, fire onDoublePinch() (§7).
        _ = simd_distance(thumbTip, indexTip)
    }
}

/// §7 — the in-scene control panel (ViewAttachment). Trimmed to what the spatial-image app
/// needs: a random-scene jump and save. (The old time-speed slider drove generated animation
/// that no longer exists; the flick-an-asteroid interaction went with the asteroid layer.)
struct ControlPanelView: View {
    @Environment(AppModel.self) private var model

    var body: some View {
        VStack(spacing: 20) {
            Button("Random Scene") { model.randomScene() }
            Button("Save This Spot") {
                // §7e capture current sceneName + thumbnail.
            }
        }
        .padding(28)
        .glassBackgroundEffect()
        .frame(width: 320)
    }
}

import SwiftUI
import RealityKit
import ARKit

/// Hosts the RealityKit scene. Since the generated L1–L4 pipeline was retired, the scene is
/// now a single `SpatialImageEnvironment` (a stereo-image inward sphere) plus the §7b whiteout
/// overlay used to mask scene changes. Spec: §7 hand tracking.
struct ImmersiveView: View {
    @Environment(AppModel.self) private var model

    var body: some View {
        RealityView { content, attachments in
            // Register the ECS components/systems the spatial scene still uses.
            ClockComponent.registerComponent()
            WhiteoutComponent.registerComponent()
            AnimationClockSystem.registerSystem()
            WhiteoutSystem.registerSystem()

            // Persistent container holds the scene; a scene change swaps the sky under it.
            let container = Entity()
            container.name = "SceneContainer"
            content.add(container)
            model.sceneContainer = container

            // The spatial-image environment — an empty container mounted now (so a select
            // works immediately) whose skybox loads async and can be swapped (currentScene).
            let scene = SpatialImageEnvironment.makeContainer()
            container.addChild(scene)
            model.sceneRoot = scene
            Task { @MainActor in
                await SpatialImageEnvironment.load(index: model.currentScene, into: scene)
            }

            // §7b whiteout overlay — a persistent inward white sphere (alpha 0) a jump flashes.
            let whiteout = WhiteoutSystem.makeEntity()
            container.addChild(whiteout)
            model.whiteout = whiteout

            // Hidden control panel, revealed by the two-hand pinch-spread gesture (§7).
            if let panel = attachments.entity(for: "controlPanel") {
                panel.isEnabled = false
                container.addChild(panel)
            }
        } update: { _, _ in
            // Scene changes are driven imperatively via AppModel (it mutates the container).
        } attachments: {
            Attachment(id: "controlPanel") {
                ControlPanelView().environment(model)
            }
        }
        .task { await runHandTracking() }   // §7 reveal gesture
        .upperLimbVisibility(.visible)
    }

    /// ARKit hand-tracking loop (90 Hz on v26+). Feeds the gesture detectors.
    private func runHandTracking() async {
        // TODO: start ARKitSession + HandTrackingProvider; route joints to
        //       DoublePinchDetector (§7).
    }
}

