import SwiftUI
import RealityKit

/// App-wide observable state. The generated L1–L4 universe was retired in favour of a fixed
/// library of pre-rendered stereo skies, so this is now just: which sky is showing, plus the
/// hooks the immersive scene needs to swap it. Spec: §7a (scene selection), §7e (saved Places).
@Observable
@MainActor
final class AppModel {
    static let immersiveSpaceID = "FloatSpace"

    enum ImmersionState { case closed, opening, open }
    var immersion: ImmersionState = .closed

    /// Index of the current sky in `SpatialImageEnvironment.catalog`.
    var currentScene: Int = 0

    /// Global animation clock (§5, foundational). Retained for future slow motion (e.g. a
    /// gentle backdrop yaw); nothing reads it while the scene is a static sphere.
    let clock = AnimationClock()

    /// Saved "Places" (§7e).
    var savedLocations: [SavedLocation] = []

    /// Set by ImmersiveView once the scene builds.
    var sceneContainer: Entity?   // persistent container
    var sceneRoot: Entity?        // the SpatialImageEnvironment sphere container
    var whiteout: Entity?         // §7b flash overlay

    // MARK: - Scene selection

    /// Show a specific sky by catalog index, masked by the §7b whiteout flash.
    func selectScene(_ index: Int) {
        let n = SpatialImageEnvironment.catalog.count
        guard n > 0 else { return }
        let idx = ((index % n) + n) % n
        currentScene = idx
        maskedSwap { [weak self] in self?.applyScene(idx) }
    }

    /// Jump to a random *different* sky. Uses a shuffle bag so every sky is visited once
    /// before any repeat (independent random draws clustered on a few). No determinism
    /// requirement here — this is a user action, not generation (§5 applied to the retired
    /// generated scene).
    func randomScene() {
        let n = SpatialImageEnvironment.catalog.count
        guard n > 1 else { if n == 1 { selectScene(0) }; return }
        if sceneBag.isEmpty {
            var bag = Array(0..<n).shuffled()
            if bag.last == currentScene { bag.swapAt(0, n - 1) }   // no immediate repeat
            sceneBag = bag
        }
        selectScene(sceneBag.removeLast())
    }

    private var sceneBag: [Int] = []

    /// Load the sky into the sphere. Falls through to the mono skybox if the stereo material
    /// or an eye can't load (SpatialImageEnvironment handles that).
    private func applyScene(_ index: Int) {
        guard let sceneRoot else { return }
        Task { @MainActor in await SpatialImageEnvironment.load(index: index, into: sceneRoot) }
    }

    /// Run `swap` under the peak of the §7b whiteout flash. Applies immediately if the overlay
    /// isn't mounted yet (e.g. a scene chosen from the launcher before entering the space).
    private func maskedSwap(_ swap: @escaping @MainActor () -> Void) {
        guard let whiteout else { swap(); return }
        if whiteout.components[WhiteoutComponent.self]?.active == true { return }
        var c = whiteout.components[WhiteoutComponent.self] ?? WhiteoutComponent()
        c.active = true; c.elapsed = 0
        whiteout.components.set(c)
        Task { @MainActor in
            try? await Task.sleep(for: .seconds(0.30))
            swap()
        }
    }
}

/// Launcher — the flat window that opens the immersive space and gives the three top-level
/// actions: a random sky, the scene picker, and the Entertainment sub-menu (Kindle / Music /
/// Video). Everything scene-related now targets the single spatial-image system.
struct LauncherView: View {
    @Environment(AppModel.self) private var model
    @Environment(\.openImmersiveSpace) private var openImmersiveSpace
    @Environment(\.openWindow) private var openWindow

    var body: some View {
        VStack(spacing: 16) {
            Text("Float").font(.extraLargeTitle)
            Text("Step into deep space.").foregroundStyle(.secondary)

            Button("Enter") {
                Task {
                    model.immersion = .opening
                    _ = await openImmersiveSpace(id: AppModel.immersiveSpaceID)
                    model.immersion = .open
                }
            }
            .buttonStyle(.borderedProminent)
            .disabled(model.immersion != .closed)

            Button("Random Scene", systemImage: "shuffle") { model.randomScene() }
                .buttonStyle(.bordered)

            Button("Scenes…", systemImage: "square.grid.2x2") { openWindow(id: "scenes") }
                .buttonStyle(.bordered)

            Button("Entertainment", systemImage: "play.rectangle.on.rectangle") {
                openWindow(id: "entertainment")
            }
            .buttonStyle(.bordered)
        }
        .padding(40)
    }
}

import SwiftUI

/// Scene picker — the one selection surface now that every scene is a stereo sky. Grounded
/// skies (real horizon, vertigo mitigation) are grouped apart from deep space. Each entry
/// shows a thumbnail (Backdrop/Thumbnails/<name>.jpg). Its own window so it can float open
/// inside the immersive space.
struct SceneSelectorView: View {
    @Environment(AppModel.self) private var model
    @State private var query = ""

    private let columns = [GridItem(.adaptive(minimum: 200), spacing: 16)]

    private func scenes(grounded: Bool) -> [(index: Int, scene: SpatialImageEnvironment.Scene)] {
        SpatialImageEnvironment.catalog.enumerated()
            .filter { $0.element.grounded == grounded }
            .filter { query.isEmpty || $0.element.title.localizedCaseInsensitiveContains(query) }
            .map { (index: $0.offset, scene: $0.element) }
    }

    var body: some View {
        NavigationStack {
            ScrollView {
                LazyVGrid(columns: columns, spacing: 16) {
                    section("Grounded", subtitle: "Real horizon — a fixed reference frame if floating brings on vertigo.",
                            items: scenes(grounded: true))
                    section("Deep Space", subtitle: nil, items: scenes(grounded: false))
                }
                .padding(20)
            }
            .navigationTitle("Scenes")
            .searchable(text: $query, prompt: "Find a scene")
        }
        .frame(minWidth: 460, minHeight: 520)
    }

    @ViewBuilder
    private func section(_ title: String, subtitle: String?,
                         items: [(index: Int, scene: SpatialImageEnvironment.Scene)]) -> some View {
        if !items.isEmpty {
            Section {
                ForEach(items, id: \.scene.id) { item in
                    SceneTile(scene: item.scene,
                              isCurrent: model.currentScene == item.index) {
                        model.selectScene(item.index)
                    }
                }
            } header: {
                VStack(alignment: .leading, spacing: 2) {
                    Text(title).font(.headline)
                    if let subtitle { Text(subtitle).font(.caption).foregroundStyle(.secondary) }
                }
                .frame(maxWidth: .infinity, alignment: .leading)
                .padding(.top, 8)
            }
        }
    }
}

/// A single thumbnail tile. Loads Backdrop/Thumbnails/<name>.jpg from the bundle; shows a
/// placeholder if it isn't there yet (e.g. before the batch conversion has produced it).
private struct SceneTile: View {
    let scene: SpatialImageEnvironment.Scene
    let isCurrent: Bool
    let action: () -> Void

    private var thumbnail: UIImage? {
        guard let url = Bundle.main.url(forResource: scene.name, withExtension: "jpg",
                                        subdirectory: "Thumbnails")
            ?? Bundle.main.url(forResource: scene.name, withExtension: "jpg")
        else { return nil }
        return UIImage(contentsOfFile: url.path)
    }

    var body: some View {
        Button(action: action) {
            VStack(alignment: .leading, spacing: 6) {
                ZStack {
                    if let img = thumbnail {
                        Image(uiImage: img).resizable().aspectRatio(2, contentMode: .fit)
                    } else {
                        Rectangle().fill(.quaternary).aspectRatio(2, contentMode: .fit)
                            .overlay(Image(systemName: "photo").foregroundStyle(.secondary))
                    }
                }
                .clipShape(RoundedRectangle(cornerRadius: 10))
                .overlay(alignment: .topTrailing) {
                    if isCurrent {
                        Image(systemName: "checkmark.circle.fill")
                            .foregroundStyle(.tint).padding(6)
                            .background(.thinMaterial, in: Circle()).padding(6)
                    }
                }
                .overlay(RoundedRectangle(cornerRadius: 10)
                    .strokeBorder(isCurrent ? Color.accentColor : .clear, lineWidth: 3))

                Text(scene.title).font(.callout).lineLimit(1)
            }
        }
        .buttonStyle(.plain)
    }
}

import SwiftUI
import AVKit
import PhotosUI

/// Entertainment sub-menu (reached from the launcher's "Entertainment" button). Collects the
/// non-scene activities: the Kindle reader (moved here from the launcher), music from the
/// Music app, and a video picked from the user's photo/media library.
struct EntertainmentMenuView: View {
    @Environment(\.openWindow) private var openWindow
    @Environment(\.openURL) private var openURL

    @State private var pickedVideo: PhotosPickerItem?
    @State private var videoURL: URL?
    @State private var loadingVideo = false

    var body: some View {
        NavigationStack {
            List {
                Section("Read") {
                    Button {
                        openWindow(id: "reader")
                    } label: {
                        Label("Kindle", systemImage: "book")
                    }
                }

                Section("Listen") {
                    // Opens the Music app so the user can play their own library. Full in-app
                    // MusicKit playback would need the MusicKit capability + authorization;
                    // launching the app is the dependency-free option.
                    Button {
                        if let url = URL(string: "music://") { openURL(url) }
                    } label: {
                        Label("Music", systemImage: "music.note")
                    }
                }

                Section("Watch") {
                    // User-selected media needs no photo-library entitlement.
                    PhotosPicker(selection: $pickedVideo, matching: .videos) {
                        Label(loadingVideo ? "Loading…" : "Video from Library",
                              systemImage: "film")
                    }
                    if let videoURL {
                        VideoPlayer(player: AVPlayer(url: videoURL))
                            .frame(height: 260)
                            .clipShape(RoundedRectangle(cornerRadius: 12))
                    }
                }
            }
            .navigationTitle("Entertainment")
        }
        .frame(minWidth: 360, minHeight: 440)
        .onChange(of: pickedVideo) { _, item in
            guard let item else { return }
            loadingVideo = true
            Task {
                videoURL = try? await item.loadTransferable(type: PickedVideo.self)?.url
                loadingVideo = false
            }
        }
    }
}

/// Copies a picked video out of the Photos sandbox into a temp file AVPlayer can stream.
private struct PickedVideo: Transferable {
    let url: URL
    static var transferRepresentation: some TransferRepresentation {
        FileRepresentation(contentType: .movie) { video in
            SentTransferredFile(video.url)
        } importing: { received in
            let dst = URL.temporaryDirectory.appendingPathComponent(
                "float-video-" + received.file.lastPathComponent)
            try? FileManager.default.removeItem(at: dst)
            try FileManager.default.copyItem(at: received.file, to: dst)
            return Self(url: dst)
        }
    }
}

